export default Object.entries(questionSets).flatMap(([topicId, questions]) =>
  questions.map(([question, options, correctAnswerIndex, shortExplanation, fullExplanation, difficulty], index) => ({
    id: `${prefixes[topicId]}_${String(index + 1).padStart(3, "0")}`,
    topicId,
    question,
    options,
    correctAnswerIndex,
    shortExplanation,
    fullExplanation,
    difficulty
  }))
);
